import React, { useEffect, useState } from 'react';
import axios from 'axios';

const STATUS_LABELS = {
  'Novo': 'Novo',
  'Retorno': 'Retorno',
  'Recepção': 'Recepção',
};
const STATUS_COLORS = {
  'Novo': "bg-[#2FA74E] text-white",  
  'Retorno': "bg-[#C58800] text-white",
  'Recepção': "bg-[#DA3648] text-white",

};

export default function ListaAgendamentos({ onEditar }) {
  const [agendamentos, setAgendamentos] = useState([]);
  const [carregando, setCarregando] = useState(true);

    // Filtros e busca
  const [busca, setBusca] = useState('');
  const [filtroData, setFiltroData] = useState('');
  const [filtroHora, setFiltroHora] = useState('');


  useEffect(() => {
    setCarregando(true);
    axios.get('/api/agendamentos')
      .then((res) => {
        setAgendamentos(res.data);
        setCarregando(false);
      })
      .catch((err) => {
        console.error('Erro ao buscar agendamentos:', err);
        setCarregando(false);
      });
  }, []);
    // Função para filtrar com base na busca e filtros de data/hora
  const filtrarAgendamentos = (lista) => {
    return lista.filter(ag => {
      const textoBusca = busca.toLowerCase();
      const campos = [
        ag.operadorNome,
        ag.auxiliarNome,
        ag.disciplinaNome,
        ag.pacienteNome,
        ag.telefone,
        ag.status
      ].map(x => x ? x.toLowerCase() : '');
      const matchTexto = campos.some(campo => campo.includes(textoBusca));
      const matchData = filtroData ? (ag.data && ag.data.startsWith(filtroData)) : true;
      const matchHora = filtroHora ? (ag.hora && ag.hora.startsWith(filtroHora)) : true;
      return matchTexto && matchData && matchHora;
    });
  };

  const agendamentosFiltrados = filtrarAgendamentos(agendamentos).slice(0, 100);


  const handleDeletar = (id) => {
    if (window.confirm('Tem certeza que deseja deletar este agendamento?')) {
      axios.delete(`/api/agendamentos/${id}`)
        .then(() => {
          setAgendamentos(agendamentos.filter(a => a.id !== id));
        })
        .catch(() => alert('Erro ao deletar agendamento'));
    }
  };

  if (carregando) return <p>Carregando agendamentos...</p>;
  if (agendamentos.length === 0) return <p>Nenhum agendamento cadastrado.</p>;

  return (

    <div className="bg-white rounded-2xl shadow p- overflow-x-auto mt-6">
            {/* Campo de busca e filtros */}
      <div className="flex flex-col md:flex-row md:items-end gap-3 p-4 pb-2">
        <div className="flex-1">
          <label className="block text-sm font-medium mb-1">Pesquisar</label>
          <input
            type="text"
            className="border rounded px-3 py-2 w-full"
            placeholder="Operador, Auxiliar, Disciplina, Paciente ou Telefone"
            value={busca}
            onChange={e => setBusca(e.target.value)}
          />
        </div>
        <div>
          <label className="block text-sm font-medium mb-1">Data</label>
          <input
            type="date"
            className="border rounded px-3 py-2"
            value={filtroData}
            onChange={e => setFiltroData(e.target.value)}
          />
        </div>
        <div>
          <label className="block text-sm font-medium mb-1">Hora</label>
          <input
            type="time"
            className="border rounded px-3 py-2"
            value={filtroHora}
            onChange={e => setFiltroHora(e.target.value)}
          />
        </div>
      </div>

      <table className="min-w-full rounded-2xl">
        <thead>
          <tr className="border-b bg-gray-100">
            <th className="px-6 py-4 text-left font-semibold">Operador</th>
            <th className="px-6 py-4 text-left font-semibold">Auxiliar</th>
            <th className="px-6 py-4 text-left font-semibold">Disciplina</th>
            <th className="px-6 py-4 text-left font-semibold">Paciente</th>
            <th className="px-6 py-4 text-left font-semibold">Telefone</th>
            <th className="px-6 py-4 text-left font-semibold">Data</th>
            <th className="px-6 py-4 text-left font-semibold">Hora</th>
            <th className="px-6 py-4 text-left font-semibold">Status</th>
            <th className="px-6 py-4 text-left font-semibold"></th>
          </tr>
        </thead>
        <tbody>
          {agendamentosFiltrados.map((ag, idx) => (
            <tr key={ag.id || idx} className="border-b last:border-b-0 hover:bg-gray-50">
              <td className="px-6 py-4">{ag.operadorNome}</td>
              <td className="px-6 py-4">{ag.auxiliarNome}</td>
              <td className="px-6 py-4">{ag.disciplinaNome}</td>
              <td className="px-6 py-4">{ag.pacienteNome}</td>
              <td className="px-6 py-4">{ag.telefone}</td>
              <td className="px-6 py-4">{ag.data ? ag.data.slice(0, 10).split('-').reverse().join('/') : ''}</td>
              <td className="px-6 py-4">{ag.hora}</td>
              <td className="px-6 py-4">
                <span
                  className={
                    "inline-block px-4 py-1 rounded-full font-semibold text-sm " +
                    (STATUS_COLORS[ag.status] || "bg-gray-200 text-gray-700")
                  }
                >
                  {STATUS_LABELS[ag.status] || ag.status}
                </span>
              </td>
              <td className="px-4 py-4 flex gap-2">
                {/* Editar */}
                <button
                  onClick={() => onEditar && onEditar(ag)}
                  className="p-1 rounded hover:bg-gray-200 transition relative group"
                  title="Editar"
                  type="button"
                >
                  <svg xmlns="http://www.w3.org/2000/svg"
                   class="h-5 w-5" 
                   viewBox="0 0 20 20" 
                   fill="gray">
  <path d="M13.586 3.586a2 2 0 112.828 2.828l-.793.793-2.828-2.828.793-.793zM11.379 5.793L3 14.172V17h2.828l8.38-8.379-2.83-2.828z" />
</svg>
                  <span className="absolute left-1/2 -translate-x-1/2 mt-8 w-max bg-gray-900 text-white text-xs rounded py-1 px-2 opacity-0 group-hover:opacity-100 pointer-events-none transition">Editar</span>
                </button>
                {/* Deletar */}
                <button
                  onClick={() => handleDeletar(ag.id)}
                  className="p-1 rounded hover:bg-gray-200 transition relative group"
                  title="Deletar"
                  type="button"
                >
                  <svg xmlns="http://www.w3.org/2000/svg" class="h-5 w-5" viewBox="0 0 20 20" fill="red">
  <path fill-rule="evenodd" d="M4.293 4.293a1 1 0 011.414 0L10 8.586l4.293-4.293a1 1 0 111.414 1.414L11.414 10l4.293 4.293a1 1 0 01-1.414 1.414L10 11.414l-4.293 4.293a1 1 0 01-1.414-1.414L8.586 10 4.293 5.707a1 1 0 010-1.414z" clip-rule="evenodd" />
</svg>




                  <span className="absolute left-1/2 -translate-x-1/2 mt-8 w-max bg-gray-900 text-white text-xs rounded py-1 px-2 opacity-0 group-hover:opacity-100 pointer-events-none transition">Deletar</span>
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}
